interfaces.definition:
interface Folder {
  id: string                              // Уникальный идентификатор папки
  name: string                            // Название папки
  icon?: 'briefcase' | 'folder' | 'person' | 'box' | 'star' | 'archive' | 'users' | 'project' | 'urgent'  // Иконка папки
}

interface AttachedFile {
  id: string                              // Уникальный идентификатор файла
  file: File                              // Объект File
}
